"""Data structures for the DWB-inspired local controller."""

from dataclasses import dataclass, field
from typing import Dict, Optional

import numpy as np


@dataclass
class RobotState:
    """Current robot state for DWB planning."""
    x: float
    y: float
    yaw: float
    linear_vel: float
    angular_vel: float


@dataclass
class Trajectory:
    """A candidate trajectory generated by the trajectory generator."""
    linear_vel: float
    angular_vel: float
    poses: np.ndarray  # shape (N, 3) — [x, y, yaw]
    total_score: float = 0.0
    critic_scores: Dict[str, float] = field(default_factory=dict)
    valid: bool = True


@dataclass
class DWBResult:
    """Result returned by the DWB controller."""
    linear_vel: float
    angular_vel: float
    trajectory: Optional[Trajectory]
    success: bool
